parameters.jsCode:
const rows = $input.all().filter(item => item.json?.category);

let categoryText = "Each line is one category in this format:\n[Category] | Description | Examples\n\n";

for (const item of rows) {
  const c = item.json.category ?? "";
  const d = item.json.description ?? "";
  const e = item.json.examples ?? "";

  categoryText += `[${c}] | ${d} | ${e}\n`;
}

return [
  {
    json: {
      category_prompt: categoryText.trim()
    }
  }
];

